This is a critical vulnerability. When Express.js receives duplicate query parameters, it creates an array, and naive checks can be bypassed through HTTP Parameter Pollution (HPP).

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

// Vulnerable: Direct use of query parameter for authorization
app.get('/api/admin/users', (req, res) => {
  const userRole = req.query.role;

  // This check can be bypassed with HPP!
  if (userRole === 'admin') {
    // Fetch and return admin data
    const users = getAllUsers();
    return res.json({ success: true, users: users });
  }

  return res.status(403).json({ error: 'Access denied' });
});

// Another vulnerable pattern: checking array loosely
app.post('/api/settings', (req, res) => {
  const permission = req.body.permission;

  // Vulnerable: truthy check on potentially polluted parameter
  if (permission == 'write') {
    updateSettings(req.body.settings);
    return res.json({ success: true });
  }

  return res.status(403).json({ error: 'No write permission' });
});

app.listen(3000);
```

**Attack Payload**:
```text
GET /api/admin/users?role=user&role=admin HTTP/1.1
Host: vulnerable-app.com

# Express parses this as: req.query.role = ['user', 'admin']
# The check userRole === 'admin' fails (array !== string)
# But some code paths may check: userRole.includes('admin') which passes!
```

**Why This Is Dangerous**:
- Express.js converts duplicate parameters into arrays automatically
- Loose equality checks (`==`) behave unexpectedly with arrays
- Authorization decisions based on client-supplied roles bypass server-side security
- Attackers can manipulate the parameter order or add duplicates to exploit parsing differences

**SECURE VERSION**:

```javascript
const express = require('express');
const hpp = require('hpp');
const jwt = require('jsonwebtoken');

const app = express();
app.use(express.json());

// DEFENSE 1: HPP middleware to prevent parameter pollution
app.use(hpp());

// DEFENSE 2: Role from authenticated session, NOT from request
const authenticate = (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = decoded; // Role comes from verified token
    next();
  } catch (err) {
    return res.status(401).json({ error: 'Invalid token' });
  }
};

// DEFENSE 3: Authorization middleware using server-side role
const requireRole = (allowedRoles) => {
  return (req, res, next) => {
    // Role from authenticated session, NEVER from request params
    const userRole = req.user?.role;

    // Strict type checking
    if (typeof userRole !== 'string') {
      return res.status(403).json({ error: 'Invalid role format' });
    }

    if (!allowedRoles.includes(userRole)) {
      console.warn(`Unauthorized access attempt: user=${req.user?.id} role=${userRole}`);
      return res.status(403).json({ error: 'Insufficient permissions' });
    }

    next();
  };
};

// Secure endpoint: role checked from JWT, not query params
app.get('/api/admin/users', authenticate, requireRole(['admin']), (req, res) => {
  const users = getAllUsers();
  res.json({ success: true, users: users });
});

app.listen(3000);
```

**Key Security Controls**:
- **HPP Middleware**: The `hpp` package automatically selects the last parameter value, preventing array injection attacks
- **Server-Side Role Source**: Authorization decisions use roles from verified JWT tokens, not user-supplied parameters
- **Strict Type Checking**: Validates that role is a string before comparison, preventing type coercion exploits

Great question! You need to explicitly define which parameters can be arrays and validate them strictly while protecting authorization-related parameters from pollution.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const hpp = require('hpp');
const { body, query, validationResult } = require('express-validator');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();
app.use(express.json());
app.use(helmet());

// LAYER 1: HPP with whitelist for legitimate array parameters
app.use(hpp({
  whitelist: ['categories', 'tags', 'ids'] // ONLY these can be arrays
}));

// LAYER 2: Rate limiting to prevent enumeration attacks
const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  message: { error: 'Too many requests, please try again later' },
  standardHeaders: true,
  legacyHeaders: false
});
app.use('/api/', apiLimiter);

// LAYER 3: Parameter sanitization and validation utility
const sanitizeArrayParam = (param, maxItems = 10, allowedValues = null) => {
  // Normalize to array
  let values = Array.isArray(param) ? param : [param];

  // Filter out non-string values
  values = values.filter(v => typeof v === 'string' && v.length > 0);

  // Limit array size to prevent DoS
  values = values.slice(0, maxItems);

  // Sanitize each value
  values = values.map(v => v.trim().toLowerCase());

  // If allowedValues provided, filter to only valid options
  if (allowedValues && Array.isArray(allowedValues)) {
    values = values.filter(v => allowedValues.includes(v));
  }

  return values;
};

// LAYER 4: Strict scalar parameter validation (for auth params)
const sanitizeScalarParam = (param) => {
  // If array was passed (HPP attempt), take first value only
  if (Array.isArray(param)) {
    console.warn('HPP attempt detected, taking first value only');
    param = param[0];
  }

  if (typeof param !== 'string') {
    return null;
  }

  return param.trim();
};

// Authentication middleware with audit logging
const authenticate = async (req, res, next) => {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const token = authHeader.split(' ')[1];
    const decoded = await verifyToken(token);

    // Audit log for security monitoring
    console.log(JSON.stringify({
      event: 'auth_success',
      userId: decoded.id,
      ip: req.ip,
      userAgent: req.get('User-Agent'),
      timestamp: new Date().toISOString()
    }));

    req.user = decoded;
    next();
  } catch (err) {
    console.log(JSON.stringify({
      event: 'auth_failure',
      reason: err.message,
      ip: req.ip,
      timestamp: new Date().toISOString()
    }));
    return res.status(401).json({ error: 'Invalid or expired token' });
  }
};

// SECURE: Endpoint accepting multiple categories (whitelisted array param)
app.get('/api/products',
  authenticate,
  [
    query('categories').optional(),
    query('page').optional().isInt({ min: 1, max: 1000 }),
    query('limit').optional().isInt({ min: 1, max: 100 })
  ],
  (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    // Safe array parameter handling with validation
    const allowedCategories = ['electronics', 'clothing', 'books', 'home', 'sports'];
    const categories = sanitizeArrayParam(
      req.query.categories,
      5, // max 5 categories
      allowedCategories
    );

    const page = parseInt(req.query.page) || 1;
    const limit = parseInt(req.query.limit) || 20;

    // Build safe query with parameterized values
    const products = getProductsByCategories(categories, page, limit);

    res.json({
      success: true,
      categories: categories,
      page: page,
      limit: limit,
      products: products
    });
  }
);

// SECURE: Admin endpoint with strict role checking
app.delete('/api/admin/products/:id',
  authenticate,
  (req, res) => {
    // CRITICAL: Role from JWT only, never from request
    const userRole = req.user.role;

    // Strict type and value check
    if (typeof userRole !== 'string' || userRole !== 'admin') {
      console.log(JSON.stringify({
        event: 'authz_failure',
        userId: req.user.id,
        attemptedAction: 'delete_product',
        productId: req.params.id,
        ip: req.ip,
        timestamp: new Date().toISOString()
      }));
      return res.status(403).json({ error: 'Admin access required' });
    }

    const productId = sanitizeScalarParam(req.params.id);
    if (!productId || !/^[a-f0-9]{24}$/.test(productId)) {
      return res.status(400).json({ error: 'Invalid product ID' });
    }

    deleteProduct(productId);

    console.log(JSON.stringify({
      event: 'admin_action',
      action: 'delete_product',
      productId: productId,
      adminId: req.user.id,
      ip: req.ip,
      timestamp: new Date().toISOString()
    }));

    res.json({ success: true, deleted: productId });
  }
);

app.listen(3000);
```

**Defense in Depth Layers**:

1. **HPP Middleware with Whitelist**: Only explicitly allowed parameters can be arrays
```javascript
app.use(hpp({
  whitelist: ['categories', 'tags'] // Others become scalar
}));
```

2. **Input Validation with express-validator**: Schema-based validation before processing
```javascript
query('categories').optional().isArray({ max: 5 }),
query('categories.*').isIn(['electronics', 'clothing', 'books'])
```

3. **Type-Safe Parameter Handlers**: Explicit sanitization with size limits
```javascript
const values = sanitizeArrayParam(param, 10, allowedValues);
```

**Additional Protections**:
- **Audit Logging**: All authorization decisions logged with context for SIEM integration
- **Rate Limiting**: Prevents brute-force parameter fuzzing attacks
- **Security Headers**: Helmet.js adds CSP, X-Frame-Options, etc.
- **Allowlist Validation**: Array parameters validated against known-good values
- **Fail Closed**: Any validation failure results in denial, not permissive fallback
- **Monitoring Alerts**: Configure alerts for repeated `authz_failure` events from same IP

Your code is vulnerable to HTTP Parameter Pollution (HPP) attacks. When an application receives multiple parameters with the same name, different frameworks handle them differently - some take the first value, some take the last, and some combine them. Attackers exploit this inconsistency to bypass authorization checks.

**VULNERABLE CODE**:

```java
import javax.servlet.http.*;
import javax.servlet.*;
import java.io.*;

public class AdminPanelServlet extends HttpServlet {

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {

        // VULNERABLE: Using getParameter() with multiple same-named params
        String role = request.getParameter("role");
        String userId = request.getParameter("userId");

        // Authorization check based on role parameter
        if ("admin".equals(role)) {
            // Grant admin access
            response.getWriter().println("Admin Dashboard - User: " + userId);
            loadAdminDashboard(response, userId);
        } else {
            response.sendError(HttpServletResponse.SC_FORBIDDEN, "Access Denied");
        }
    }

    private void loadAdminDashboard(HttpServletResponse response, String userId) 
            throws IOException {
        // Load sensitive admin functionality
        response.getWriter().println("Sensitive admin operations available");
    }
}
```

**Attack Payload**:
```text
GET /admin?role=user&role=admin HTTP/1.1
Host: vulnerable-app.com
```

Or via POST body:
```text
role=user&role=admin&userId=12345
```

**Why This Is Dangerous**:
- `getParameter()` returns only the FIRST parameter in Java servlets, but upstream proxies/WAFs may check the LAST one
- A WAF might see `role=user` and allow the request, while the servlet processes `role=admin` (or vice versa depending on proxy behavior)
- The role parameter comes from user input instead of server-side session data
- No validation that the userId matches the authenticated user

**SECURE VERSION**:

```java
import javax.servlet.http.*;
import javax.servlet.*;
import java.io.*;
import java.util.logging.Logger;

public class SecureAdminPanelServlet extends HttpServlet {
    private static final Logger LOGGER = Logger.getLogger(SecureAdminPanelServlet.class.getName());

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {

        // SECURE: Detect and reject parameter pollution attempts
        if (hasParameterPollution(request, "role") || hasParameterPollution(request, "userId")) {
            LOGGER.warning("Parameter pollution attempt from IP: " + request.getRemoteAddr());
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid request");
            return;
        }

        // SECURE: Get role from authenticated session, NOT from request parameters
        HttpSession session = request.getSession(false);
        if (session == null) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Not authenticated");
            return;
        }

        String authenticatedUserId = (String) session.getAttribute("userId");
        String userRole = (String) session.getAttribute("role");

        if (authenticatedUserId == null || userRole == null) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Session invalid");
            return;
        }

        // SECURE: Server-side role check from trusted session data
        if ("admin".equals(userRole)) {
            LOGGER.info("Admin access granted to user: " + authenticatedUserId);
            loadAdminDashboard(response, authenticatedUserId);
        } else {
            LOGGER.warning("Unauthorized admin access attempt by user: " + authenticatedUserId);
            response.sendError(HttpServletResponse.SC_FORBIDDEN, "Access Denied");
        }
    }

    private boolean hasParameterPollution(HttpServletRequest request, String paramName) {
        String[] values = request.getParameterValues(paramName);
        return values != null && values.length > 1;
    }

    private void loadAdminDashboard(HttpServletResponse response, String userId) 
            throws IOException {
        response.setContentType("text/html");
        response.getWriter().println("Admin Dashboard - User: " + escapeHtml(userId));
    }

    private String escapeHtml(String input) {
        if (input == null) return "";
        return input.replace("&", "&amp;").replace("<", "&lt;")
                    .replace(">", "&gt;").replace("\"", "&quot;");
    }
}
```

**Key Security Controls**:
- **Parameter pollution detection**: Uses `getParameterValues()` to detect multiple values for same parameter and rejects such requests
- **Session-based authorization**: Role information comes from server-controlled session, not user-controlled parameters
- **Defense in depth**: Multiple validation layers before granting access
- **Audit logging**: Suspicious requests are logged with client IP for forensic analysis

For production Spring Boot REST APIs, you need a comprehensive defense strategy that includes request filtering, centralized authorization, and monitoring. Here's an enterprise-grade approach that handles parameter pollution and other authorization attacks.

**PRODUCTION PATTERN**:

```java
package com.example.security;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
import org.springframework.web.filter.OncePerRequestFilter;
import org.springframework.stereotype.Component;
import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.web.bind.annotation.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import javax.servlet.FilterChain;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.util.*;
import java.util.regex.Pattern;

@SpringBootApplication
public class SecureApiApplication {
    public static void main(String[] args) {
        SpringApplication.run(SecureApiApplication.class, args);
    }
}

// LAYER 1: Parameter Pollution Detection Filter
@Component
public class ParameterPollutionFilter extends OncePerRequestFilter {
    private static final Logger logger = LoggerFactory.getLogger(ParameterPollutionFilter.class);

    // Parameters that should NEVER have multiple values
    private static final Set<String> SENSITIVE_PARAMS = Set.of(
        "role", "userId", "admin", "permission", "access_level",
        "token", "session_id", "auth", "grant_type"
    );

    // Maximum allowed values for any parameter
    private static final int MAX_PARAM_VALUES = 5;

    @Override
    protected void doFilterInternal(HttpServletRequest request,
                                    HttpServletResponse response,
                                    FilterChain filterChain)
            throws ServletException, IOException {

        Map<String, String[]> parameterMap = request.getParameterMap();

        for (Map.Entry<String, String[]> entry : parameterMap.entrySet()) {
            String paramName = entry.getKey().toLowerCase();
            String[] values = entry.getValue();

            // Check sensitive parameters for pollution
            if (SENSITIVE_PARAMS.contains(paramName) && values.length > 1) {
                logger.warn("SECURITY: Parameter pollution detected - param={}, values={}, ip={}, uri={}",
                    paramName, values.length, request.getRemoteAddr(), request.getRequestURI());

                response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
                response.setContentType("application/json");
                response.getWriter().write("{\"error\":\"Invalid request parameters\"}");
                return;
            }

            // Reject excessive parameter values (DoS protection)
            if (values.length > MAX_PARAM_VALUES) {
                logger.warn("SECURITY: Excessive parameter values - param={}, count={}, ip={}",
                    paramName, values.length, request.getRemoteAddr());

                response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
                response.getWriter().write("{\"error\":\"Too many parameter values\"}");
                return;
            }
        }

        filterChain.doFilter(request, response);
    }
}

// LAYER 2: Security Configuration
@Configuration
@EnableWebSecurity
@EnableMethodSecurity(prePostEnabled = true)
public class SecurityConfig {

    private final ParameterPollutionFilter pollutionFilter;

    public SecurityConfig(ParameterPollutionFilter pollutionFilter) {
        this.pollutionFilter = pollutionFilter;
    }

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            .addFilterBefore(pollutionFilter, UsernamePasswordAuthenticationFilter.class)
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/api/admin/**").hasRole("ADMIN")
                .requestMatchers("/api/user/**").hasAnyRole("USER", "ADMIN")
                .requestMatchers("/api/public/**").permitAll()
                .anyRequest().authenticated()
            )
            .csrf(csrf -> csrf.disable()) // Disable for REST API with tokens
            .sessionManagement(session -> session
                .maximumSessions(1)
                .maxSessionsPreventsLogin(true)
            );

        return http.build();
    }
}

// LAYER 3: Secure Controller with Method-Level Authorization
@RestController
@RequestMapping("/api/admin")
public class AdminController {
    private static final Logger logger = LoggerFactory.getLogger(AdminController.class);
    private static final Pattern VALID_USER_ID = Pattern.compile("^[a-zA-Z0-9]{1,36}$");

    @GetMapping("/users/{userId}")
    @PreAuthorize("hasRole('ADMIN') and @authorizationService.canAccessUser(authentication, #userId)")
    public ResponseEntity<?> getUserDetails(
            @PathVariable String userId,
            @AuthenticationPrincipal UserDetails currentUser) {

        // Input validation
        if (!VALID_USER_ID.matcher(userId).matches()) {
            logger.warn("Invalid userId format attempted by {}: {}", 
                currentUser.getUsername(), userId);
            return ResponseEntity.badRequest()
                .body(Map.of("error", "Invalid user ID format"));
        }

        // Audit log
        logger.info("Admin {} accessed user details for {}", 
            currentUser.getUsername(), userId);

        // Business logic with user from path (validated and authorized)
        return ResponseEntity.ok(fetchUserDetails(userId));
    }

    @PostMapping("/permissions")
    @PreAuthorize("hasRole('SUPER_ADMIN')")
    public ResponseEntity<?> updatePermissions(
            @Valid @RequestBody PermissionUpdateRequest request,
            @AuthenticationPrincipal UserDetails currentUser) {

        // Request object validates via Bean Validation - no pollution possible
        logger.info("Permission update by {} for target {}: {}",
            currentUser.getUsername(), request.getTargetUserId(), request.getPermissions());

        return ResponseEntity.ok(Map.of("status", "updated"));
    }

    private Map<String, Object> fetchUserDetails(String userId) {
        return Map.of("userId", userId, "status", "active");
    }
}

// LAYER 4: Custom Authorization Service for Complex Rules
@Service
public class AuthorizationService {
    private static final Logger logger = LoggerFactory.getLogger(AuthorizationService.class);

    public boolean canAccessUser(Authentication auth, String targetUserId) {
        // Super admins can access any user
        if (auth.getAuthorities().stream()
                .anyMatch(a -> a.getAuthority().equals("ROLE_SUPER_ADMIN"))) {
            return true;
        }

        // Regular admins can only access users in their organization
        String adminOrg = extractOrganization(auth);
        String targetOrg = getUserOrganization(targetUserId);

        boolean authorized = adminOrg != null && adminOrg.equals(targetOrg);

        if (!authorized) {
            logger.warn("Authorization denied: {} attempted to access user {} (org mismatch)",
                auth.getName(), targetUserId);
        }

        return authorized;
    }

    private String extractOrganization(Authentication auth) {
        // Extract from JWT claims or session
        return "org-123"; // Placeholder
    }

    private String getUserOrganization(String userId) {
        // Lookup from database
        return "org-123"; // Placeholder
    }
}

// Request DTO with Bean Validation (prevents parameter manipulation)
public class PermissionUpdateRequest {
    @NotBlank
    @Pattern(regexp = "^[a-zA-Z0-9]{1,36}$")
    private String targetUserId;

    @NotEmpty
    @Size(max = 10)
    private List<@Pattern(regexp = "^[A-Z_]{1,50}$") String> permissions;

    // Getters and setters
    public String getTargetUserId() { return targetUserId; }
    public void setTargetUserId(String targetUserId) { this.targetUserId = targetUserId; }
    public List<String> getPermissions() { return permissions; }
    public void setPermissions(List<String> permissions) { this.permissions = permissions; }
}
```

**Defense in Depth Layers**:

1. **Request Filter Layer**: Intercepts ALL requests before reaching controllers, detecting parameter pollution on sensitive parameter names and blocking requests with excessive values

2. **Spring Security Layer**: Declarative URL-based security with role requirements, session management to prevent session fixation

3. **Method Security Layer**: `@PreAuthorize` annotations with SpEL expressions for fine-grained authorization based on business rules

4. **Authorization Service Layer**: Centralized complex authorization logic with organization-based access control and comprehensive audit logging

**Additional Protections**:

- **Use DTOs with Bean Validation**: Request body objects with `@Valid` prevent parameter manipulation since JSON binding creates a single typed object
- **Path variables over query parameters**: `@PathVariable` for identifiers is safer than query params for sensitive values
- **Typed binding**: Spring automatically converts to proper types, reducing injection risks
- **Rate limiting**: Add `@RateLimiter` from resilience4j for DoS protection:

```java
@GetMapping("/sensitive")
@RateLimiter(name = "adminApi", fallbackMethod = "rateLimitFallback")
public ResponseEntity<?> sensitiveOperation() {
    // Implementation
}
```

- **Security monitoring**: Integrate with SIEM for real-time alerting:

```java
@EventListener
public void handleAuthorizationDenied(AuthorizationDeniedEvent event) {
    securityMetrics.incrementCounter("authorization.denied");
    alertingService.sendAlert("Authorization denied", event.getDetails());
}
```

HTTP Parameter Pollution (HPP) is a serious authorization bypass vulnerability where attackers submit multiple parameters with the same name to confuse your application's access control logic.

**VULNERABLE CODE**:

```go
package main

import (
	"database/sql"
	"encoding/json"
	"net/http"
	"strconv"

	_ "github.com/lib/pq"
)

type UserProfile struct {
	ID    int    `json:"id"`
	Name  string `json:"name"`
	Email string `json:"email"`
	Role  string `json:"role"`
}

var db *sql.DB

// VULNERABLE: Uses first parameter for auth, but backend might use different one
func getProfile(w http.ResponseWriter, r *http.Request) {
	// Get user_id from query - r.URL.Query().Get() returns FIRST value only
	userIDStr := r.URL.Query().Get("user_id")
	requestingUser := r.URL.Query().Get("requesting_user")

	userID, err := strconv.Atoi(userIDStr)
	if err != nil {
		http.Error(w, "Invalid user ID", http.StatusBadRequest)
		return
	}

	// Authorization check uses the first user_id parameter
	if userIDStr != requestingUser {
		http.Error(w, "Forbidden", http.StatusForbidden)
		return
	}

	// Database query - but what if there are multiple user_id params?
	// Some middleware/proxies may forward the LAST value instead
	var profile UserProfile
	err = db.QueryRow(
		"SELECT id, name, email, role FROM users WHERE id = $1",
		userID,
	).Scan(&profile.ID, &profile.Name, &profile.Email, &profile.Role)

	if err != nil {
		http.Error(w, "User not found", http.StatusNotFound)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(profile)
}
```

**Attack Payload**:
```text
GET /api/profile?user_id=123&requesting_user=123&user_id=456 HTTP/1.1
Host: api.example.com

# Frontend/auth middleware checks first user_id (123) = requesting_user (123) ✓
# But reverse proxy forwards last user_id (456) to database query
# Attacker (user 123) accesses victim's (user 456) profile!
```

**Why This Is Dangerous**:
- Different frameworks parse duplicate parameters differently (first vs last vs array)
- Reverse proxies (nginx, HAProxy) may modify parameter order or selection
- Authorization checks can be bypassed when validation uses different param than execution
- WAFs and security middleware may inspect different parameter instances

**SECURE VERSION**:

```go
package main

import (
	"database/sql"
	"encoding/json"
	"log"
	"net/http"
	"strconv"

	_ "github.com/lib/pq"
)

type UserProfile struct {
	ID    int    `json:"id"`
	Name  string `json:"name"`
	Email string `json:"email"`
	Role  string `json:"role"`
}

var db *sql.DB

// SECURE: Detect and reject parameter pollution attempts
func getProfileSecure(w http.ResponseWriter, r *http.Request) {
	queryParams := r.URL.Query()

	// DEFENSE 1: Reject requests with duplicate parameters
	if len(queryParams["user_id"]) > 1 {
		log.Printf("SECURITY: Parameter pollution attempt from %s - multiple user_id values",
			r.RemoteAddr)
		http.Error(w, "Invalid request: duplicate parameters", http.StatusBadRequest)
		return
	}

	userIDStr := queryParams.Get("user_id")
	if userIDStr == "" {
		http.Error(w, "Missing user_id parameter", http.StatusBadRequest)
		return
	}

	// DEFENSE 2: Strict input validation
	userID, err := strconv.Atoi(userIDStr)
	if err != nil || userID <= 0 {
		http.Error(w, "Invalid user ID format", http.StatusBadRequest)
		return
	}

	// DEFENSE 3: Get authenticated user from secure session, NOT from parameters
	authenticatedUserID := getAuthenticatedUserID(r)
	if authenticatedUserID == 0 {
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	// DEFENSE 4: Authorization check against trusted session data
	if userID != authenticatedUserID && !isAdmin(authenticatedUserID) {
		log.Printf("SECURITY: Unauthorized access attempt - user %d tried to access profile %d",
			authenticatedUserID, userID)
		http.Error(w, "Forbidden", http.StatusForbidden)
		return
	}

	var profile UserProfile
	err = db.QueryRow(
		"SELECT id, name, email, role FROM users WHERE id = $1",
		userID,
	).Scan(&profile.ID, &profile.Name, &profile.Email, &profile.Role)

	if err != nil {
		http.Error(w, "User not found", http.StatusNotFound)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(profile)
}

func getAuthenticatedUserID(r *http.Request) int {
	// Extract from validated JWT or secure session - NOT from request params
	// This is set by authentication middleware
	if userID, ok := r.Context().Value("authenticated_user_id").(int); ok {
		return userID
	}
	return 0
}

func isAdmin(userID int) bool {
	var role string
	err := db.QueryRow("SELECT role FROM users WHERE id = $1", userID).Scan(&role)
	return err == nil && role == "admin"
}
```

**Key Security Controls**:
- **Duplicate parameter detection**: Explicitly check for and reject multiple values for sensitive parameters
- **Trusted identity source**: Get user identity from validated session/JWT, never from untrusted request parameters
- **Consistent parameter handling**: Use single source of truth for authorization decisions
- **Security logging**: Log parameter pollution attempts for incident detection

When legitimate functionality requires array parameters, you need strict validation and explicit handling to prevent parameter pollution attacks.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"regexp"
	"strconv"
	"strings"
	"time"

	_ "github.com/lib/pq"
)

type Document struct {
	ID      int    `json:"id"`
	Title   string `json:"title"`
	OwnerID int    `json:"owner_id"`
}

type APIResponse struct {
	Success   bool        `json:"success"`
	Data      interface{} `json:"data,omitempty"`
	Error     string      `json:"error,omitempty"`
	RequestID string      `json:"request_id"`
}

const (
	MaxArrayParams     = 100
	MaxParamValueLen   = 50
	RateLimitPerMinute = 60
)

var (
	db             *sql.DB
	auditLogger    *log.Logger
	securityLogger *log.Logger
	idArrayRegex   = regexp.MustCompile(`^[0-9,]+$`)
)

// ParameterValidator provides safe parameter extraction with pollution detection
type ParameterValidator struct {
	request    *http.Request
	requestID  string
	violations []string
}

func NewParameterValidator(r *http.Request, requestID string) *ParameterValidator {
	return &ParameterValidator{
		request:   r,
		requestID: requestID,
	}
}

// GetSingleParam extracts a parameter that MUST be singular
func (pv *ParameterValidator) GetSingleParam(name string) (string, bool) {
	values := pv.request.URL.Query()[name]

	if len(values) == 0 {
		return "", true // Not present, which may be valid
	}

	if len(values) > 1 {
		pv.violations = append(pv.violations,
			fmt.Sprintf("parameter '%s' appeared %d times (expected 1)", name, len(values)))
		return "", false
	}

	value := strings.TrimSpace(values[0])
	if len(value) > MaxParamValueLen {
		pv.violations = append(pv.violations,
			fmt.Sprintf("parameter '%s' exceeds max length", name))
		return "", false
	}

	return value, true
}

// GetArrayParam extracts array params with strict bracket notation: ids[]=1&ids[]=2
func (pv *ParameterValidator) GetArrayParam(name string) ([]string, bool) {
	// CRITICAL: Only accept explicit array notation to prevent pollution
	arrayKey := name + "[]"

	// Check for pollution attempts via non-array key
	if values := pv.request.URL.Query()[name]; len(values) > 0 {
		pv.violations = append(pv.violations,
			fmt.Sprintf("parameter '%s' must use array notation '%s'", name, arrayKey))
		return nil, false
	}

	values := pv.request.URL.Query()[arrayKey]

	if len(values) > MaxArrayParams {
		pv.violations = append(pv.violations,
			fmt.Sprintf("array parameter '%s' exceeds max count %d", name, MaxArrayParams))
		return nil, false
	}

	// Validate each value
	for i, v := range values {
		if len(v) > MaxParamValueLen {
			pv.violations = append(pv.violations,
				fmt.Sprintf("array parameter '%s[%d]' exceeds max length", name, i))
			return nil, false
		}
	}

	return values, true
}

// GetIntArray extracts and validates integer array parameters
func (pv *ParameterValidator) GetIntArray(name string) ([]int, bool) {
	strValues, ok := pv.GetArrayParam(name)
	if !ok {
		return nil, false
	}

	if len(strValues) == 0 {
		return []int{}, true
	}

	result := make([]int, 0, len(strValues))
	seen := make(map[int]bool)

	for _, s := range strValues {
		val, err := strconv.Atoi(strings.TrimSpace(s))
		if err != nil || val <= 0 {
			pv.violations = append(pv.violations,
				fmt.Sprintf("invalid integer value '%s' in array '%s'", s, name))
			return nil, false
		}

		// Deduplicate to prevent amplification attacks
		if !seen[val] {
			seen[val] = true
			result = append(result, val)
		}
	}

	return result, true
}

func (pv *ParameterValidator) HasViolations() bool {
	return len(pv.violations) > 0
}

func (pv *ParameterValidator) LogViolations(remoteAddr string) {
	if len(pv.violations) > 0 {
		securityLogger.Printf("PARAM_POLLUTION request_id=%s ip=%s violations=%v",
			pv.requestID, remoteAddr, pv.violations)
	}
}

// PRODUCTION HANDLER: Get documents filtered by IDs with full protection
func getDocumentsHandler(w http.ResponseWriter, r *http.Request) {
	requestID := generateRequestID()
	ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
	defer cancel()

	// Set security headers
	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("X-Content-Type-Options", "nosniff")
	w.Header().Set("X-Request-ID", requestID)

	// LAYER 1: Parameter validation with pollution detection
	validator := NewParameterValidator(r, requestID)

	// Single-value params - reject duplicates
	pageStr, ok := validator.GetSingleParam("page")
	if !ok {
		validator.LogViolations(r.RemoteAddr)
		respondError(w, "Invalid request parameters", http.StatusBadRequest, requestID)
		return
	}

	// Array param - require explicit array notation
	documentIDs, ok := validator.GetIntArray("document_ids")
	if !ok {
		validator.LogViolations(r.RemoteAddr)
		respondError(w, "Invalid request parameters", http.StatusBadRequest, requestID)
		return
	}

	if validator.HasViolations() {
		validator.LogViolations(r.RemoteAddr)
		respondError(w, "Invalid request parameters", http.StatusBadRequest, requestID)
		return
	}

	// LAYER 2: Get authenticated user from secure context
	authUserID := getAuthenticatedUserIDFromContext(r)
	if authUserID == 0 {
		respondError(w, "Unauthorized", http.StatusUnauthorized, requestID)
		return
	}

	page := 1
	if pageStr != "" {
		var err error
		page, err = strconv.Atoi(pageStr)
		if err != nil || page < 1 || page > 1000 {
			respondError(w, "Invalid page number", http.StatusBadRequest, requestID)
			return
		}
	}

	// LAYER 3: Authorization-aware database query
	documents, err := fetchAuthorizedDocuments(ctx, authUserID, documentIDs, page)
	if err != nil {
		log.Printf("ERROR request_id=%s error=%v", requestID, err)
		respondError(w, "Internal server error", http.StatusInternalServerError, requestID)
		return
	}

	// LAYER 4: Audit logging
	auditLogger.Printf("DOCUMENT_ACCESS request_id=%s user_id=%d document_count=%d ip=%s",
		requestID, authUserID, len(documents), r.RemoteAddr)

	respondSuccess(w, documents, requestID)
}

// Authorization is enforced AT THE DATABASE LEVEL - user can only see their documents
func fetchAuthorizedDocuments(ctx context.Context, userID int, documentIDs []int, page int) ([]Document, error) {
	limit := 50
	offset := (page - 1) * limit

	var query string
	var args []interface{}

	if len(documentIDs) == 0 {
		// No filter - get all user's documents
		query = `
			SELECT id, title, owner_id 
			FROM documents 
			WHERE owner_id = $1 
			ORDER BY id 
			LIMIT $2 OFFSET $3`
		args = []interface{}{userID, limit, offset}
	} else {
		// Filter by IDs - but ONLY return user's documents (authorization enforced)
		placeholders := make([]string, len(documentIDs))
		args = make([]interface{}, 0, len(documentIDs)+3)
		args = append(args, userID)

		for i, id := range documentIDs {
			placeholders[i] = fmt.Sprintf("$%d", i+2)
			args = append(args, id)
		}

		args = append(args, limit, offset)

		query = fmt.Sprintf(`
			SELECT id, title, owner_id 
			FROM documents 
			WHERE owner_id = $1 AND id IN (%s)
			ORDER BY id 
			LIMIT $%d OFFSET $%d`,
			strings.Join(placeholders, ","),
			len(documentIDs)+2,
			len(documentIDs)+3)
	}

	rows, err := db.QueryContext(ctx, query, args...)
	if err != nil {
		return nil, fmt.Errorf("query failed: %w", err)
	}
	defer rows.Close()

	var documents []Document
	for rows.Next() {
		var doc Document
		if err := rows.Scan(&doc.ID, &doc.Title, &doc.OwnerID); err != nil {
			return nil, fmt.Errorf("scan failed: %w", err)
		}
		documents = append(documents, doc)
	}

	return documents, rows.Err()
}

func getAuthenticatedUserIDFromContext(r *http.Request) int {
	if userID, ok := r.Context().Value("authenticated_user_id").(int); ok {
		return userID
	}
	return 0
}

func generateRequestID() string {
	return fmt.Sprintf("%d", time.Now().UnixNano())
}

func respondError(w http.ResponseWriter, message string, code int, requestID string) {
	w.WriteHeader(code)
	json.NewEncoder(w).Encode(APIResponse{
		Success:   false,
		Error:     message,
		RequestID: requestID,
	})
}

func respondSuccess(w http.ResponseWriter, data interface{}, requestID string) {
	json.NewEncoder(w).Encode(APIResponse{
		Success:   true,
		Data:      data,
		RequestID: requestID,
	})
}
```

**Defense in Depth Layers**:

1. **Explicit Parameter Notation**:
```go
// ONLY accept ids[]=1&ids[]=2, reject ids=1&ids=2
arrayKey := name + "[]"
if values := pv.request.URL.Query()[name]; len(values) > 0 {
    // Reject ambiguous parameter usage
    return nil, false
}
```

2. **Parameter Count Limits**:
```go
if len(values) > MaxArrayParams {
    // Prevent resource exhaustion via parameter flooding
    return nil, false
}
```

3. **Database-Level Authorization**:
```go
// Even if attacker pollutes IDs, query enforces owner_id check
WHERE owner_id = $1 AND id IN (...)
// User can ONLY access their own documents regardless of requested IDs
```

**Additional Protections**:
- **Request ID tracking**: Every request gets unique ID for correlation in security incidents
- **Deduplication**: Array values are deduplicated to prevent amplification attacks
- **Timeout contexts**: Database queries have strict timeouts to prevent DoS
- **Separate security logging**: Parameter pollution attempts logged to dedicated security log for SIEM integration
- **Consistent error messages**: Don't reveal which validation failed to attackers

Using `$_REQUEST` for authorization checks is dangerous because it combines `$_GET`, `$_POST`, and `$_COOKIE` values, making your application vulnerable to HTTP Parameter Pollution (HPP) attacks. Attackers can manipulate which value takes precedence by sending the same parameter through different channels.

**VULNERABLE CODE**:

```php
<?php
// Vulnerable authorization check using $_REQUEST
class DocumentController {
    private $pdo;

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    public function viewDocument() {
        // VULNERABLE: Using $_REQUEST allows parameter pollution
        $user_id = $_REQUEST['user_id'];
        $doc_id = $_REQUEST['doc_id'];
        $role = $_REQUEST['role'];

        // Attacker can pollute 'role' parameter
        if ($role === 'admin' || $this->isDocumentOwner($user_id, $doc_id)) {
            return $this->fetchDocument($doc_id);
        }

        http_response_code(403);
        return ['error' => 'Access denied'];
    }

    private function isDocumentOwner($user_id, $doc_id) {
        $stmt = $this->pdo->prepare("SELECT owner_id FROM documents WHERE id = ?");
        $stmt->execute([$doc_id]);
        $doc = $stmt->fetch();
        return $doc && $doc['owner_id'] == $user_id;
    }

    private function fetchDocument($doc_id) {
        $stmt = $this->pdo->prepare("SELECT * FROM documents WHERE id = ?");
        $stmt->execute([$doc_id]);
        return $stmt->fetch(PDO::FETCH_ASSOC);
    }
}
```

**Attack Payload**:
```text
GET /document.php?doc_id=1337&role=user HTTP/1.1
Host: example.com
Cookie: role=admin

// Or via POST pollution:
POST /document.php?role=admin HTTP/1.1
Content-Type: application/x-www-form-urlencoded

doc_id=1337&user_id=123&role=user
```

**Why This Is Dangerous**:
- `$_REQUEST` merges GET, POST, and COOKIE with configurable precedence (default: GPCS)
- Attackers can inject 'role=admin' via cookies while sending 'role=user' in GET
- Server-side frameworks may parse duplicate parameters differently than expected
- Authorization decisions based on user-controllable 'role' parameter bypass session-based auth

**SECURE VERSION**:

```php
<?php
class SecureDocumentController {
    private $pdo;
    private $session;

    public function __construct($pdo, SessionHandler $session) {
        $this->pdo = $pdo;
        $this->session = $session;
    }

    public function viewDocument(): array {
        // SECURE: Get user info from authenticated session only
        $user = $this->session->getAuthenticatedUser();
        if (!$user) {
            http_response_code(401);
            return ['error' => 'Authentication required'];
        }

        // SECURE: Use specific superglobal, validate input
        $doc_id = filter_input(INPUT_GET, 'doc_id', FILTER_VALIDATE_INT);
        if ($doc_id === false || $doc_id === null) {
            http_response_code(400);
            return ['error' => 'Invalid document ID'];
        }

        // SECURE: Check authorization from server-side session data
        if (!$this->canAccessDocument($user['id'], $user['role'], $doc_id)) {
            $this->logUnauthorizedAccess($user['id'], $doc_id);
            http_response_code(403);
            return ['error' => 'Access denied'];
        }

        return $this->fetchDocument($doc_id);
    }

    private function canAccessDocument(int $user_id, string $role, int $doc_id): bool {
        // Check role from session, not from request
        if ($role === 'admin') {
            return true;
        }

        // Verify ownership in database
        $stmt = $this->pdo->prepare(
            "SELECT 1 FROM documents WHERE id = ? AND (owner_id = ? OR is_public = 1)"
        );
        $stmt->execute([$doc_id, $user_id]);
        return $stmt->fetch() !== false;
    }

    private function logUnauthorizedAccess(int $user_id, int $doc_id): void {
        error_log(sprintf(
            "[SECURITY] Unauthorized access attempt: user=%d, doc=%d, ip=%s",
            $user_id,
            $doc_id,
            $_SERVER['REMOTE_ADDR'] ?? 'unknown'
        ));
    }

    private function fetchDocument(int $doc_id): array {
        $stmt = $this->pdo->prepare("SELECT id, title, content FROM documents WHERE id = ?");
        $stmt->execute([$doc_id]);
        return $stmt->fetch(PDO::FETCH_ASSOC) ?: ['error' => 'Document not found'];
    }
}
```

**Key Security Controls**:
- **Session-based authorization**: User roles are retrieved from server-side session, never from request parameters
- **Explicit input source**: Use `filter_input(INPUT_GET, ...)` instead of `$_REQUEST` to specify exact parameter source
- **Input validation**: Validate and sanitize all user input with appropriate filters
- **Audit logging**: Log all unauthorized access attempts for security monitoring

For applications requiring flexible parameter sources with complex authorization, you need a robust input validation layer combined with a proper Role-Based Access Control (RBAC) or Attribute-Based Access Control (ABAC) system. Here's a production-ready pattern that prevents parameter pollution while supporting sophisticated permission models.

**PRODUCTION PATTERN**:

```php
<?php
declare(strict_types=1);

/**
 * Secure Input Handler - Prevents Parameter Pollution
 */
class SecureInputHandler {
    private array $allowedSources = [];
    private array $processedParams = [];

    public function __construct(array $config) {
        $this->allowedSources = $config;
    }

    public function get(string $param, string $source = 'GET'): mixed {
        // Validate source is allowed for this parameter
        if (!$this->isSourceAllowed($param, $source)) {
            throw new SecurityException(
                "Parameter '$param' not allowed from source '$source'"
            );
        }

        // Detect parameter pollution attempts
        if ($this->detectPollution($param)) {
            $this->logPollutionAttempt($param);
            throw new SecurityException('Parameter pollution detected');
        }

        $value = match($source) {
            'GET' => filter_input(INPUT_GET, $param),
            'POST' => filter_input(INPUT_POST, $param),
            'COOKIE' => filter_input(INPUT_COOKIE, $param),
            default => throw new InvalidArgumentException("Invalid source: $source")
        };

        $this->processedParams[$param] = $source;
        return $value;
    }

    private function isSourceAllowed(string $param, string $source): bool {
        return isset($this->allowedSources[$param]) 
            && in_array($source, $this->allowedSources[$param], true);
    }

    private function detectPollution(string $param): bool {
        $sources = [
            'GET' => $_GET[$param] ?? null,
            'POST' => $_POST[$param] ?? null,
            'COOKIE' => $_COOKIE[$param] ?? null
        ];

        $presentIn = array_filter($sources, fn($v) => $v !== null);

        // If same param exists in multiple sources, it's pollution
        return count($presentIn) > 1;
    }

    private function logPollutionAttempt(string $param): void {
        error_log(sprintf(
            "[SECURITY] HPP attempt detected: param=%s, ip=%s, uri=%s",
            $param,
            $_SERVER['REMOTE_ADDR'] ?? 'unknown',
            $_SERVER['REQUEST_URI'] ?? 'unknown'
        ));
    }
}

/**
 * Permission Service - RBAC with Attribute Checks
 */
class PermissionService {
    private PDO $pdo;
    private array $permissionCache = [];

    public function __construct(PDO $pdo) {
        $this->pdo = $pdo;
    }

    public function hasPermission(
        int $userId, 
        string $resource, 
        string $action,
        array $context = []
    ): bool {
        $cacheKey = "{$userId}:{$resource}:{$action}";

        if (isset($this->permissionCache[$cacheKey])) {
            return $this->permissionCache[$cacheKey];
        }

        // Check explicit permissions
        $hasExplicit = $this->checkExplicitPermission($userId, $resource, $action);

        // Check role-based permissions
        $hasRole = $this->checkRolePermission($userId, $resource, $action);

        // Check resource-specific ownership/attributes
        $hasAttribute = $this->checkAttributePermission($userId, $resource, $action, $context);

        $result = $hasExplicit || $hasRole || $hasAttribute;
        $this->permissionCache[$cacheKey] = $result;

        return $result;
    }

    private function checkExplicitPermission(int $userId, string $resource, string $action): bool {
        $stmt = $this->pdo->prepare("
            SELECT 1 FROM user_permissions 
            WHERE user_id = ? AND resource = ? AND action = ? AND granted = 1
        ");
        $stmt->execute([$userId, $resource, $action]);
        return $stmt->fetch() !== false;
    }

    private function checkRolePermission(int $userId, string $resource, string $action): bool {
        $stmt = $this->pdo->prepare("
            SELECT 1 FROM role_permissions rp
            JOIN user_roles ur ON rp.role_id = ur.role_id
            WHERE ur.user_id = ? AND rp.resource = ? AND rp.action = ?
        ");
        $stmt->execute([$userId, $resource, $action]);
        return $stmt->fetch() !== false;
    }

    private function checkAttributePermission(
        int $userId, 
        string $resource, 
        string $action,
        array $context
    ): bool {
        // Resource-specific ownership checks
        if (isset($context['resource_id'])) {
            $table = $this->sanitizeTableName($resource);
            $stmt = $this->pdo->prepare(
                "SELECT owner_id FROM {$table} WHERE id = ?"
            );
            $stmt->execute([$context['resource_id']]);
            $row = $stmt->fetch();

            if ($row && (int)$row['owner_id'] === $userId) {
                return in_array($action, ['read', 'update', 'delete'], true);
            }
        }

        return false;
    }

    private function sanitizeTableName(string $resource): string {
        // Whitelist allowed table names
        $allowed = ['documents', 'projects', 'reports', 'files'];
        if (!in_array($resource, $allowed, true)) {
            throw new InvalidArgumentException('Invalid resource type');
        }
        return $resource;
    }
}

/**
 * Secure Controller with Full Authorization
 */
class ProductionDocumentController {
    private PDO $pdo;
    private SecureInputHandler $input;
    private PermissionService $permissions;
    private SessionHandler $session;
    private RateLimiter $rateLimiter;

    public function __construct(
        PDO $pdo,
        SecureInputHandler $input,
        PermissionService $permissions,
        SessionHandler $session,
        RateLimiter $rateLimiter
    ) {
        $this->pdo = $pdo;
        $this->input = $input;
        $this->permissions = $permissions;
        $this->session = $session;
        $this->rateLimiter = $rateLimiter;
    }

    public function handleRequest(): array {
        try {
            // Layer 1: Rate limiting
            if (!$this->rateLimiter->check($_SERVER['REMOTE_ADDR'], 'document_api')) {
                http_response_code(429);
                return ['error' => 'Too many requests'];
            }

            // Layer 2: Authentication
            $user = $this->session->getAuthenticatedUser();
            if (!$user) {
                http_response_code(401);
                return ['error' => 'Authentication required'];
            }

            // Layer 3: CSRF protection
            if ($_SERVER['REQUEST_METHOD'] === 'POST') {
                if (!$this->validateCsrfToken()) {
                    http_response_code(403);
                    return ['error' => 'Invalid request token'];
                }
            }

            // Layer 4: Secure input handling (prevents HPP)
            $docId = (int)$this->input->get('doc_id', 'GET');
            if ($docId <= 0) {
                http_response_code(400);
                return ['error' => 'Invalid document ID'];
            }

            // Layer 5: Authorization check
            $action = $this->getRequestedAction();
            if (!$this->permissions->hasPermission(
                $user['id'],
                'documents',
                $action,
                ['resource_id' => $docId]
            )) {
                $this->logAuthorizationFailure($user['id'], $docId, $action);
                http_response_code(403);
                return ['error' => 'Access denied'];
            }

            // Layer 6: Execute authorized action
            return $this->executeAction($action, $docId, $user);

        } catch (SecurityException $e) {
            error_log("[SECURITY] " . $e->getMessage());
            http_response_code(400);
            return ['error' => 'Invalid request'];
        } catch (Exception $e) {
            error_log("[ERROR] " . $e->getMessage());
            http_response_code(500);
            return ['error' => 'Internal server error'];
        }
    }

    private function validateCsrfToken(): bool {
        $token = filter_input(INPUT_POST, 'csrf_token');
        return $token && hash_equals($this->session->getCsrfToken(), $token);
    }

    private function getRequestedAction(): string {
        return match($_SERVER['REQUEST_METHOD']) {
            'GET' => 'read',
            'POST' => 'create',
            'PUT', 'PATCH' => 'update',
            'DELETE' => 'delete',
            default => throw new InvalidArgumentException('Invalid method')
        };
    }

    private function executeAction(string $action, int $docId, array $user): array {
        $this->logAccess($user['id'], $docId, $action);

        return match($action) {
            'read' => $this->readDocument($docId),
            'update' => $this->updateDocument($docId),
            'delete' => $this->deleteDocument($docId),
            default => throw new InvalidArgumentException('Invalid action')
        };
    }

    private function readDocument(int $docId): array {
        $stmt = $this->pdo->prepare(
            "SELECT id, title, content, created_at FROM documents WHERE id = ?"
        );
        $stmt->execute([$docId]);
        return $stmt->fetch(PDO::FETCH_ASSOC) ?: ['error' => 'Not found'];
    }

    private function logAccess(int $userId, int $docId, string $action): void {
        $stmt = $this->pdo->prepare(
            "INSERT INTO access_log (user_id, resource_id, action, ip_address, timestamp) 
