    public class ProductsController : ControllerBase
    {
        private readonly ILogger<ProductsController> _logger;
        private readonly IProductService _productService;

        public ProductsController(
            ILogger<ProductsController> logger,
            IProductService productService)
        {
            _logger = logger;
            _productService = productService;
        }

        /// <summary>
        /// Secure endpoint accepting legitimate array parameters
        /// </summary>
        [HttpGet("search")]
        public IActionResult SearchProducts([FromQuery] ProductSearchRequest request)
        {
            // Model binding handles array params safely
            // ids[] parameter becomes List<int> Ids property

            // Validate array contents, not just structure
            if (request.Ids?.Any(id => id <= 0) == true)
            {
                return BadRequest("Invalid product ID");
            }

            if (request.Categories?.Any(c => !IsValidCategory(c)) == true)
            {
                return BadRequest("Invalid category");
            }

            var results = _productService.Search(request);
            return Ok(results);
        }

        /// <summary>
        /// Endpoint that explicitly rejects multi-value for security params
        /// </summary>
        [HttpGet("{id}")]
        public IActionResult GetProduct(
            int id,
            [FromQuery] string accessLevel) // Single value only
        {
            // The ParameterPollutionProtection filter already blocked
            // any attempts to send multiple accessLevel values

            // Additional validation: accessLevel must be from allowed list
            var allowedLevels = new[] { "public", "member", "premium" };
            if (!string.IsNullOrEmpty(accessLevel) && 
                !allowedLevels.Contains(accessLevel.ToLower()))
            {
                _logger.LogWarning("Invalid access level requested: {Level}", accessLevel);
                return BadRequest("Invalid access level");
            }

            var product = _productService.GetById(id, accessLevel);
            return product != null ? Ok(product) : NotFound();
        }

        private bool IsValidCategory(string category)
        {
            // Whitelist validation
            var validCategories = new[] 
            { 
                "electronics", "clothing", "books", "home", "sports" 
            };
            return validCategories.Contains(category?.ToLower());
        }
    }

    public class ProductSearchRequest
    {
