HTTP Parameter Pollution (HPP) is a critical vulnerability where attackers send duplicate query parameters to bypass authorization checks. Different parsers handle duplicates differently - some take the first value, some take the last, and Express.js returns an array. This inconsistency can bypass access controls.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

// Middleware to check if user can access resource
function checkOwnership(req, res, next) {
  const userId = req.query.userId;
  const resourceOwnerId = req.query.ownerId;

  // VULNERABLE: Does not handle arrays from duplicate params
  if (userId === resourceOwnerId) {
    next();
  } else {
    res.status(403).json({ error: 'Access denied' });
  }
}

app.get('/api/documents', checkOwnership, (req, res) => {
  const userId = req.query.userId;

  // Fetch documents - but which userId is used?
  // If userId is an array, this query may behave unexpectedly
  const query = `SELECT * FROM documents WHERE owner_id = '${userId}'`;

  // Execute query and return results
  res.json({ documents: [] });
});

app.listen(3000);
```

**Attack Payload**:
```text
GET /api/documents?userId=attacker123&ownerId=attacker123&userId=victim456
```

**Why This Is Dangerous**:
- Express parses duplicate `userId` as an array: `['attacker123', 'victim456']`
- The `===` comparison with a string `ownerId` fails in unexpected ways
- When array is coerced to string in SQL, it becomes `'attacker123,victim456'` or only uses first/last element
- Downstream code may use a different array element than the authorization check
- Attacker bypasses ownership check and accesses victim's documents

**SECURE VERSION**:

```javascript
const express = require('express');
const hpp = require('hpp');
const app = express();

// HPP middleware - takes last value for duplicate params
app.use(hpp());

// Strict parameter extraction utility
function getStringParam(value, paramName) {
  if (Array.isArray(value)) {
    console.warn(`HPP attempt detected on param: ${paramName}`);
    // Take first value or reject - be consistent
    return String(value[0]);
  }
  if (typeof value !== 'string') {
    throw new Error(`Invalid parameter type for ${paramName}`);
  }
  return value;
}

// Secure ownership check middleware
function checkOwnership(req, res, next) {
  try {
    const userId = getStringParam(req.query.userId, 'userId');
    const resourceOwnerId = getStringParam(req.query.ownerId, 'ownerId');

    // Validate format (UUID in this case)
    const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
    if (!uuidRegex.test(userId) || !uuidRegex.test(resourceOwnerId)) {
      return res.status(400).json({ error: 'Invalid ID format' });
    }

    // Store validated values for downstream use
    req.validatedParams = { userId, resourceOwnerId };

    if (userId === resourceOwnerId) {
      next();
    } else {
      res.status(403).json({ error: 'Access denied' });
    }
  } catch (error) {
    res.status(400).json({ error: 'Invalid parameters' });
  }
}

app.get('/api/documents', checkOwnership, (req, res) => {
  // Use validated params, not raw query params
  const { userId } = req.validatedParams;

  // Parameterized query (using validated value)
  // db.query('SELECT * FROM documents WHERE owner_id = $1', [userId]);

  res.json({ documents: [] });
});

app.listen(3000);
```

**Key Security Controls**:
- **HPP Middleware**: Uses `hpp` package to normalize duplicate parameters
- **Type Enforcement**: Explicitly checks and converts parameter types
- **Validated Parameter Store**: Uses `req.validatedParams` so downstream handlers use same values as authorization check
- **Format Validation**: UUID regex ensures IDs match expected format
- **Consistent Handling**: Always uses same parsing strategy across authorization and data access

Yes, parameter pollution can occur in JSON bodies through duplicate keys, prototype pollution, or mixed sources (query + body + headers). When combined with role-based access control, this becomes even more dangerous as attackers can attempt privilege escalation.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const hpp = require('hpp');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { body, query, validationResult } = require('express-validator');
const winston = require('winston');

const app = express();

// Security logger
const securityLogger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

// Core security middleware
app.use(helmet());
app.use(hpp({ whitelist: [] })); // No params allowed to be arrays
app.use(express.json({ limit: '10kb' })); // Limit body size

// Rate limiting for sensitive endpoints
const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: { error: 'Too many requests' }
});

// Role hierarchy
const ROLE_HIERARCHY = {
  'admin': 100,
  'manager': 50,
  'user': 10,
  'guest': 0
};

// Secure JSON body parser that rejects duplicate keys
function parseSecureJSON(jsonString) {
  const seen = new Set();
  return JSON.parse(jsonString, (key, value) => {
    if (key !== '' && seen.has(key)) {
      throw new Error(`Duplicate key detected: ${key}`);
    }
    seen.add(key);
    return value;
  });
}

// Middleware to prevent parameter source mixing
function preventParamMixing(allowedSources = ['body']) {
  return (req, res, next) => {
    const sources = {
      query: Object.keys(req.query).length > 0,
      body: Object.keys(req.body || {}).length > 0,
      params: Object.keys(req.params).length > 0
    };

    const activeSources = Object.entries(sources)
      .filter(([_, hasData]) => hasData)
      .map(([source]) => source);

    const disallowedSources = activeSources.filter(s => !allowedSources.includes(s));

    if (disallowedSources.length > 0) {
      securityLogger.warn({
        event: 'param_source_violation',
        ip: req.ip,
        disallowed: disallowedSources,
        path: req.path
      });
      return res.status(400).json({ error: 'Invalid request format' });
    }
    next();
  };
}

// Secure RBAC middleware factory
function requireRole(minimumRole) {
  return async (req, res, next) => {
    try {
      // Get user from verified JWT (set by auth middleware)
      const user = req.authenticatedUser;

      if (!user || !user.role) {
        securityLogger.warn({
          event: 'missing_auth',
          ip: req.ip,
          path: req.path
        });
        return res.status(401).json({ error: 'Authentication required' });
      }

      // CRITICAL: Role comes from verified token, NOT request params
      const userRoleLevel = ROLE_HIERARCHY[user.role];
      const requiredLevel = ROLE_HIERARCHY[minimumRole];

      if (userRoleLevel === undefined || requiredLevel === undefined) {
        securityLogger.error({
          event: 'invalid_role',
          userRole: user.role,
          requiredRole: minimumRole
        });
        return res.status(500).json({ error: 'Configuration error' });
      }

      if (userRoleLevel < requiredLevel) {
        securityLogger.warn({
          event: 'access_denied',
          userId: user.id,
          userRole: user.role,
          requiredRole: minimumRole,
          path: req.path
        });
        return res.status(403).json({ error: 'Insufficient permissions' });
      }

      // Log successful authorization
      securityLogger.info({
        event: 'access_granted',
        userId: user.id,
        role: user.role,
        path: req.path
      });

      next();
    } catch (error) {
      securityLogger.error({ event: 'auth_error', error: error.message });
      res.status(500).json({ error: 'Authorization error' });
    }
  };
}

// Ownership check that prevents HPP
function requireOwnership(resourceIdParam = 'id') {
  return async (req, res, next) => {
    const user = req.authenticatedUser;

    // Extract resource ID from validated params only
    let resourceId = req.params[resourceIdParam];

    // Reject if array (HPP attempt)
    if (Array.isArray(resourceId)) {
      securityLogger.warn({
        event: 'hpp_attempt',
        param: resourceIdParam,
        ip: req.ip
      });
      return res.status(400).json({ error: 'Invalid parameter format' });
    }

    // Fetch resource and check ownership
    // const resource = await db.getResource(resourceId);
    const resource = { ownerId: 'user123' }; // Placeholder

    if (!resource) {
      return res.status(404).json({ error: 'Resource not found' });
    }

    // Admins can access anything
    if (ROLE_HIERARCHY[user.role] >= ROLE_HIERARCHY['admin']) {
      req.resource = resource;
      return next();
    }

    // Others must own the resource
    if (resource.ownerId !== user.id) {
      securityLogger.warn({
        event: 'ownership_violation',
        userId: user.id,
        resourceOwner: resource.ownerId,
        resourceId: resourceId
      });
      return res.status(403).json({ error: 'Access denied' });
    }

    req.resource = resource;
    next();
  };
}

