    if (targetUserId === req.authenticatedUser.id) {
      return res.status(400).json({ error: 'Cannot modify own role' });
    }

    securityLogger.info({
      event: 'role_change',
      actor: req.authenticatedUser.id,
      target: targetUserId,
      newRole: newRole
    });

    // await db.updateUserRole(targetUserId, newRole);
    res.json({ success: true });
  }
);

app.listen(3000);
